import type { Type } from "arktype"
import { jsonSchemaToType } from "@ark/json-schema"

/**
 * TODO: Implement the bidirectional ArkType <-> JSON Schema round trip.
 *
 * `roundTrip(schema)` MUST:
 *   1. Export `schema` to JSON Schema (draft-2020-12) via `schema.toJsonSchema()`.
 *   2. Re-parse the resulting JSON Schema back into an ArkType `Type` using
 *      `@ark/json-schema`.
 *   3. Return the re-parsed Type.
 */
export function roundTrip(schema: Type): Type {
  return jsonSchemaToType(exportJsonSchema(schema)) as Type
}

/**
 * TODO: Implement the JSON Schema export used as the round-trip intermediate.
 * The returned object MUST contain `$schema` set to the draft-2020-12 URI:
 *   https://json-schema.org/draft/2020-12/schema
 */
export function exportJsonSchema(schema: Type): object {
  const jsonSchema = schema.toJsonSchema()
  return {
    $schema: "https://json-schema.org/draft/2020-12/schema",
    ...jsonSchema
  }
}

import { type } from "arktype"
import { exportJsonSchema, roundTrip } from "./roundTrip.js"

async function main() {
  const chunks: Buffer[] = []
  for await (const chunk of process.stdin) {
    chunks.push(Buffer.from(chunk))
  }
  const inputString = Buffer.concat(chunks).toString("utf-8")

  if (!inputString.trim()) {
    process.exit(1)
  }

  const input = JSON.parse(inputString)
  const schemaDef = input.schema
  const corpus = input.corpus

  const originalType = type(schemaDef)
  const jsonSchema = exportJsonSchema(originalType)
  const roundTrippedType = roundTrip(originalType)

  const agreements = []
  let allAgree = true

  for (let i = 0; i < corpus.length; i++) {
    const payload = corpus[i]
    const originalAccept = !originalType(payload).errors
    const roundTrippedAccept = !roundTrippedType(payload).errors
    const agree = originalAccept === roundTrippedAccept

    if (!agree) {
      allAgree = false
    }

    agreements.push({
      index: i,
      originalAccept,
      roundTrippedAccept,
      agree
    })
  }

  const output = {
    jsonSchema,
    agreements,
    allAgree
  }

  console.log(JSON.stringify(output, null, 2))

  if (allAgree) {
    process.exit(0)
  } else {
    process.exit(1)
  }
}

main().catch(err => {
  console.error(err)
  process.exit(1)
})

